    /// </summary>
    SensorGps = 4,
    /// <summary>
    /// Represents FAILURE_UNIT_SENSOR_OPTICAL_FLOW.
    /// </summary>
    SensorOpticalFlow = 5,
    /// <summary>
    /// Represents FAILURE_UNIT_SENSOR_VIO.
    /// </summary>
    SensorVio = 6,
    /// <summary>
    /// Represents FAILURE_UNIT_SENSOR_DISTANCE_SENSOR.
    /// </summary>
    SensorDistanceSensor = 7,
    /// <summary>
    /// Represents FAILURE_UNIT_SENSOR_AIRSPEED.
    /// </summary>
    SensorAirspeed = 8,
    /// <summary>
    /// Represents FAILURE_UNIT_SYSTEM_BATTERY.
    /// </summary>
    SystemBattery = 100,
    /// <summary>
    /// Interrupts the commanded output to the motor.
    /// </summary>
    SystemMotor = 101,
    /// <summary>
    /// Represents FAILURE_UNIT_SYSTEM_SERVO.
