    /// </summary>
    NavLoiterTime = 19,
    /// <summary>
    /// Return to launch location
    /// </summary>
    NavReturnToLaunch = 20,
    /// <summary>
    /// Land at location.
    /// </summary>
    NavLand = 21,
    /// <summary>
    /// Takeoff from ground / hand. Vehicles that support multiple takeoff modes (e.g. VTOL quadplane) should take off using the currently configured mode.
    /// </summary>
    NavTakeoff = 22,
    /// <summary>
    /// Land at local position (local frame only)
    /// </summary>
    NavLandLocal = 23,
    /// <summary>
    /// Takeoff from local position (local frame only)
    /// </summary>
    NavTakeoffLocal = 24,
    /// <summary>
    /// Vehicle following, i.e. this waypoint represents the position of a moving vehicle
    /// </summary>
    NavFollow = 25,
    /// <summary>
    /// Continue on the current course and climb/descend to specified altitude. When the altitude is reached continue to the next command (i.e., don&#39;t proceed to the next command until the desired altitude is reached.
    /// </summary>
    NavContinueAndChangeAlt = 30,
    /// <summary>
    /// Begin loiter at the specified Latitude and Longitude. If Lat=Lon=0, then loiter at the current position. Don&#39;t consider the navigation command complete (don&#39;t leave loiter) until the altitude has been reached. Additionally, if the Heading Required parameter is non-zero the aircraft will not leave the loiter until heading toward the next waypoint.
    /// </summary>
    NavLoiterToAlt = 31,
    /// <summary>
    /// Begin following a target
    /// </summary>
    DoFollow = 32,
    /// <summary>
    /// Reposition the MAV after a follow target command has been sent
    /// </summary>
    DoFollowReposition = 33,
    /// <summary>
    /// Start orbiting on the circumference of a circle defined by the parameters. Setting values to NaN/INT32_MAX (as appropriate) results in using defaults.
    /// </summary>
    DoOrbit = 34,
    /// <summary>
    /// Fly a figure eight path as defined by the parameters. Set parameters to NaN/INT32_MAX (as appropriate) to use system-default values. The command is intended for fixed wing vehicles (and VTOL hybrids flying in fixed-wing mode), allowing POI tracking for gimbals that don&#39;t support infinite rotation. This command only defines the flight path. Speed should be set independently (use e.g. MAV_CMD_DO_CHANGE_SPEED). Yaw and other degrees of freedom are not specified, and will be flight-stack specific (on vehicles where they can be controlled independent of the heading).
    /// </summary>
    DoFigureEight = 35,
    /// <summary>
    /// Circular arc path waypoint. This defines the end/exit point and angle (param1) of an arc path from the previous waypoint. A position is required before this command to define the start of the arc (e.g. current position, a MAV_CMD_NAV_WAYPOINT, or a MAV_CMD_NAV_ARC_WAYPOINT). The resulting path is a circular arc in the NE frame, with the difference in height being defined by the difference in waypoint altitudes.
    /// </summary>
    NavArcWaypoint = 36,
    /// <summary>
    /// Sets the region of interest (ROI) for a sensor set or the vehicle itself. This can then be used by the vehicle&#39;s control system to control the vehicle attitude and the attitude of various sensors such as cameras.
    /// </summary>
    NavRoi = 80,
    /// <summary>
    /// Control autonomous path planning on the MAV.
    /// </summary>
    NavPathplanning = 81,
    /// <summary>
    /// Navigate to waypoint using a spline path.
    /// </summary>
    NavSplineWaypoint = 82,
    /// <summary>
    /// Mission command to wait for an altitude or downwards vertical speed. This is meant for high altitude balloon launches, allowing the aircraft to be idle until either an altitude is reached or a negative vertical speed is reached (indicating early balloon burst). The wiggle time is how often to wiggle the control surfaces to prevent them seizing up.
    /// </summary>
    NavAltitudeWait = 83,
    /// <summary>
    /// Takeoff from ground using VTOL mode, and transition to forward flight with specified heading. The command should be ignored by vehicles that dont support both VTOL and fixed-wing flight (multicopters, boats,etc.).
    /// </summary>
    NavVtolTakeoff = 84,
