    /// </summary>
    Emergency = 6,
    /// <summary>
    /// System just initialized its power-down sequence, will shut down now.
    /// </summary>
    Poweroff = 7,
    /// <summary>
    /// System is terminating itself (failsafe or commanded).
    /// </summary>
    FlightTermination = 8,
}

